css:
       :root {
            --primary: #f97316;
            --primary-dark: #ea580c;
            --bg: #f8fafc;
            --text: #1e293b;
            --text-light: #64748b;
            --border: #e2e8f0;
            --card-bg: #ffffff;
            /* 実画面のボタン色 */
            --btn-blue: #2563eb;
            --btn-orange: #f97316;
            /* ページ管理の新規作成など：アクセント */
            --btn-red: #dc2626;
            --btn-gray: #64748b;
            --btn-new: #2563eb;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
            line-height: 1.7;
            color: var(--text);
            background-color: var(--bg);
            margin: 0;
            display: flex;
        }

        nav.sidebar {
            width: 280px;
            height: 100vh;
            position: sticky;
            top: 0;
            background: #fff;
            border-right: 1px solid var(--border);
            padding: 20px;
            overflow-y: auto;
            box-sizing: border-box;
        }

        nav.sidebar h2 {
            font-size: 1.2rem;
            margin-bottom: 20px;
            color: var(--primary);
        }

        nav.sidebar ul {
            list-style: none;
            padding: 0;
        }

        nav.sidebar li {
            margin-bottom: 8px;
        }

        nav.sidebar a {
            text-decoration: none;
            color: var(--text-light);
            font-size: 0.9rem;
            transition: color 0.2s;
        }

        nav.sidebar a:hover {
            color: var(--primary);
        }

        main {
            flex: 1;
            max-width: 800px;
            padding: 40px 60px;
            background: #fff;
            min-height: 100vh;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.05);
        }

        h1 {
            font-size: 2.2rem;
            border-bottom: 4px solid var(--primary);
            padding-bottom: 10px;
            margin-bottom: 40px;
        }

        h2 {
            font-size: 1.6rem;
            border-left: 6px solid var(--primary);
            padding-left: 15px;
            margin-top: 50px;
            margin-bottom: 25px;
        }

        h2.black {
            border-left-color: #333;
            color: #333;
        }

        h3 {
            font-size: 1.3rem;
            margin-top: 35px;
            color: var(--primary-dark);
        }

        h3.black {
            color: #333;
            border-bottom: 1px solid #eee;
            padding-bottom: 5px;
        }

        p {
            margin-bottom: 20px;
        }

        ul,
        ol {
            margin-bottom: 20px;
        }

        code {
            background: #f1f5f9;
            padding: 2px 6px;
            border-radius: 4px;
            font-family: monospace;
            font-size: 1.1em;
        }

        pre {
            background: #1e293b;
            color: #f8fafc;
            padding: 20px;
            border-radius: 8px;
            overflow-x: auto;
            margin: 20px 0;
        }

        table {
            width: 100%;
            border-collapse: collapse;
            margin: 20px 0;
        }

        th,
        td {
            border: 1px solid var(--border);
            padding: 12px 15px;
            text-align: left;
        }

        th {
            background: #f1f5f9;
            font-weight: bold;
        }

        /* ボタン（バッジ）デザイン */
        .m-btn {
            display: inline-flex;
            align-items: center;
            gap: 4px;
            padding: 2px 10px;
            border-radius: 4px;
            font-size: 0.85rem;
            font-weight: bold;
            color: #fff;
            vertical-align: middle;
            margin: 0 2px;
            line-height: 1.5;
        }

        .m-btn .material-symbols-outlined {
            font-size: 1em;
        }

        .m-btn-blue {
            background: var(--btn-blue);
        }

        .m-btn-orange {
            background: var(--btn-orange);
        }

        /* 実画面の新規作成等 */
        .m-btn-red {
            background: var(--btn-red);
        }

        .m-btn-gray {
            background: var(--btn-gray);
        }

        .type-badge {
            display: inline-block;
            padding: 2px 8px;
            border-radius: 4px;
            font-size: 0.8rem;
            font-weight: bold;
            color: #fff;
            vertical-align: middle;
            white-space: nowrap;
        }

        .badge-green {
            background: #10b981;
        }

        .badge-gray {
            background: #64748b;
        }

        .field-desc {
            margin-bottom: 40px;
            padding-bottom: 20px;
        }

        .field-item {
            font-weight: bold;
            color: #1e293b;
            display: block;
            margin-top: 20px;
            font-size: 1.1rem;
        }

        .field-item::before {
            content: '■ ';
            color: var(--primary);
        }
